function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    if (n === 0) return 0;

    let baseProfit = 0;
    const A: number[] = new Array(n);
    for (let i = 0; i < n; i++) {
        A[i] = strategy[i] * prices[i];
        baseProfit += A[i];
    }

    const prefixP: number[] = [0];
    const prefixA: number[] = [0];

    for (let i = 0; i < n; i++) {
        prefixP.push(prefixP[i] + prices[i]);
        prefixA.push(prefixA[i] + A[i]);
    }

    const halfK = k >> 1;
    let bestDelta = 0;

    for (let start = 0; start <= n - k; start++) {
        const end = start + k - 1;
        const mid = start + halfK;

        const newValue = prefixP[end + 1] - prefixP[mid];
        const oldValue = prefixA[end + 1] - prefixA[start];

        const delta = newValue - oldValue;
        if (delta > bestDelta) {
            bestDelta = delta;
        }
    }

    return baseProfit + bestDelta;
}
```

